#include<bits/stdc++.h>
using namespace std;
const long long N=50010,M=300010;
long long head[N],now[N],tot=1,id[N],d[N],f[N],n,m,s,t,res,pre[N];
bool vis[N];
struct edge
{
    long long to,flow,cost,nxt;
}e[M];
void add1(long long u,long long v,long long w,long long c)
{
    e[++tot]={v,w,c,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w,long long c)
{
    add1(u,v,w,c);
}
bool spfa()
{
    memset(f,0x3f,sizeof(f));
    memset(d,0x3f,sizeof(d));
    long long inf=d[0];
    d[s]=0;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        vis[t]=false;
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].flow,cost=e[i].cost;
            if(val&&d[v]>max(d[t],cost))
            {
                pre[v]=t;
                d[v]=max(d[t],cost);
                f[v]=min(f[t],val);
                id[v]=i;
                if(!vis[v])
                {
                    vis[v]=true;
                    q.push(v);
                }
            }
        }
    }
    return d[t]<inf;
}
long long p;
long long solve()
{
    long long ans=0;
    while(spfa())
    {
        ans+=f[t];
        res=max(res,d[t]);
        if(ans>=p)
        {
            return 0;
        }
        long long x=t;
        while(x!=s)
        {
            e[id[x]].flow-=f[t];
            e[id[x]^1].flow+=f[t];
            x=pre[x];
        }
    }
    return 0;
}
int main()
{
    scanf("%lld%lld%lld",&n,&m,&p);
    s=1,t=n;
    for(long long i=1;i<=m;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        add(u,v,1,w);
        add(v,u,1,w);
    }
    solve();
    printf("%lld",res);
    return 0;
}
